//nonLinearOrdinalScale.js

import { d3_map } from '../core/d3-constants';

export var nonLinearOrdinalScale = function() {
    var range, domain, rangeBands, rangeExtent, ranges, rangeBand;

    function scale(x) {
        if (range) {
            return range.get(x);
        }
        return null;
    }

    scale.domain = function(_) {
        if (!arguments.length) {
            return domain;
        }
        domain = _;
        return scale;
    };

    scale.rangeBand = function(_) {
        if (!arguments.length) {
            return 0; //Dummy rangeband for proper tickTransform and tickExit in d3.v3
        }
        rangeBand = _;
        return scale;
    };

    scale.bandwidth = function(x) {
        if (!rangeBands) {
            return null;
        }
        if (arguments.length) {
            return rangeBands.get(x);
        }
        return rangeBand;
    };

    scale.rangeBands = function(x) {
        if (!arguments.length) {
            return rangeBands;
        }
        if (x == null) {
            return scale;
        }
        ranges = x;
        rangeBands = new d3_map();
        range = new d3_map();
        var i = -1,
            n = x.length,
            temp = 0;
        while (++i < n) {
            range.set(i, x[i][0]);
            rangeBands.set(i, x[i][1] - x[i][0]);
        }
        return scale;
    };

    scale.discreteWidth = function(x) {
        if (!rangeBands) {
            return null;
        }
        return rangeBands.get(x);
    };

    scale.range = function(_) {
        if (!arguments.length) {
            return rangeExtent;
        }
        rangeExtent = _;
        return scale;
    };

    scale.copy = function() {
        return nonLinearOrdinalScale()
            .domain(domain)
            .rangeBands(ranges)
            .range(rangeExtent);
    };

    return scale;
};
